-- Keep the public blog and the CMS aligned around Supabase as the only source of truth.
with category_rows as (
  select *
  from jsonb_to_recordset($json$[{"name":"Convivencia","slug":"convivencia","description":"Ideas para hablar de dinero en pareja y ordenar acuerdos del hogar."},{"name":"Método","slug":"metodo","description":"Sistemas sencillos para presupuestos, revisiones y hábitos financieros."},{"name":"Objetivos","slug":"objetivos","description":"Ahorro, planes compartidos y metas financieras con fecha real."},{"name":"Pareja","slug":"pareja","description":"Cuentas comunes, independencia y acuerdos compartidos."},{"name":"Ahorro","slug":"ahorro","description":"Gastos invisibles, suscripciones y pequeñas decisiones de ahorro."},{"name":"Rituales","slug":"rituales","description":"Hábitos ligeros para revisar dinero compartido con calma."}]$json$::jsonb)
    as item(name text, slug text, description text)
)
insert into public.blog_categories (name, slug, description)
select name, slug, description
from category_rows
on conflict (slug) do update
set name = excluded.name,
    description = excluded.description;

with post_rows as (
  select *
  from jsonb_to_recordset($json$[{"title":"Cómo hablar de dinero en pareja sin que se convierta en discusión","slug":"hablar-de-dinero-en-pareja","excerpt":"Tres rituales sencillos para que la conversación financiera deje de tensar la convivencia y empiece a sumar.","content":"Hablar de dinero en pareja suele activar una mezcla incómoda de vergüenza, control y miedo. No es casual: la mayoría aprendimos a gestionar las finanzas personales en silencio, sin un marco común para decidir juntos ni una forma clara de repartir gastos compartidos.\n\nEl primer paso no es hacer un Excel perfecto, sino acordar un momento fijo. Media hora a la semana basta para mirar ingresos, gastos del hogar, ahorro y deudas con calma. Sin móvil, sin pantalla del trabajo y sin reproches sobre la compra del sábado.\n\nConviene empezar la conversación por hechos, no por interpretaciones. Cuánto ha entrado, cuánto ha salido, qué pagos quedan pendientes y qué objetivo compartido necesita atención. Cuando la conversación financiera se apoya en datos, baja la sensación de ataque personal.\n\nEl segundo paso es separar tres cajas: lo común, lo personal y lo que se ahorra para objetivos compartidos. En lo común entran alquiler, supermercado, recibos, seguros y gastos de convivencia. En lo personal entra lo que cada uno gasta sin rendir cuentas. La tercera caja protege viajes, mudanzas, colchón de emergencia o cualquier plan de futuro.\n\nTambién ayuda decidir una regla de aportación. Algunas parejas prefieren el 50/50; otras aportan según ingresos para que el esfuerzo sea proporcional. No hay una fórmula única para las finanzas en pareja, pero sí una señal clara: si una persona siente que siempre pierde, el sistema no está funcionando.\n\nEl tercero es revisar, no juzgar. Una revisión mensual permite ajustar categorías, detectar gastos invisibles y corregir sin convertir cada error en una discusión. Karma Financiero te da el mapa; la conversación la sostenéis vosotros. Y sí, también vale celebrar cuando el mes cuadra.","featured_image":"/blog/blog-dinero-pareja-cover.jpg","category":"convivencia","author":"Karma Financiero","status":"published","published_at":"2026-06-12T09:00:00.000Z","seo_title":"Cómo hablar de dinero en pareja sin que se convierta en discusión","seo_description":"Tres rituales sencillos para que la conversación financiera deje de tensar la convivencia y empiece a sumar."},{"title":"Un presupuesto del hogar que no te robe el domingo","slug":"presupuesto-hogar-sin-estres","excerpt":"Olvida las hojas de cálculo infinitas. Así montas un sistema ligero que aguanta los meses raros y los gastos imprevistos.","content":"Un presupuesto del hogar útil no es el que prevé cada céntimo, sino el que sobrevive al primer imprevisto sin que tires todo a la basura. La clave está en pocas categorías, márgenes generosos y una revisión mensual que no robe el domingo.\n\nEmpieza con cinco bloques: vivienda, vida diaria, transporte, ocio y ahorro. Esta estructura cubre la mayoría de finanzas domésticas sin convertir el control de gastos en una tarea infinita. Si una categoría necesita demasiadas subcategorías, probablemente estás buscando precisión donde necesitas claridad.\n\nAsigna un porcentaje aproximado a cada bloque y deja un 10% sin etiquetar para lo que siempre aparece: cumpleaños, una avería, un recambio, una cena familiar o un capricho compartido. Ese margen evita que un gasto normal se viva como fracaso.\n\nPara organizar gastos familiares, separa los pagos fijos de los variables. Los fijos son alquiler, hipoteca, seguros o suscripciones. Los variables son supermercado, transporte, ocio, farmacia o regalos. Mirarlos juntos ayuda a entender dónde se puede ajustar sin recortar lo importante.\n\nRegistrar movimientos no tiene que ser un trabajo extra. Hazlo en bloques de dos minutos al día o, mejor, en una revisión semanal con tu convivencia. Si tardas más de diez minutos, el sistema es demasiado complejo y acabará abandonado.\n\nEl presupuesto también debe tener memoria. Revisa qué categorías se pasan todos los meses y cambia el límite antes de culparte. Un buen método financiero no intenta que el hogar sea perfecto; intenta que sea legible.\n\nY recuerda: el objetivo no es ahorrar más este mes, sino sostener el método doce meses seguidos. Ahí es donde aparece el verdadero karma financiero: menos ruido, más decisiones compartidas y una economía doméstica que se entiende.","featured_image":"/blog/blog-presupuesto-hogar-cover.jpg","category":"metodo","author":"Karma Financiero","status":"published","published_at":"2026-06-05T09:00:00.000Z","seo_title":"Un presupuesto del hogar que no te robe el domingo","seo_description":"Olvida las hojas de cálculo infinitas. Así montas un sistema ligero que aguanta los meses raros y los gastos imprevistos."},{"title":"Objetivos compartidos: del 'algún día' al primer paso real","slug":"objetivos-financieros-compartidos","excerpt":"Viajar, mudarse, formar familia, dejar un trabajo. Convierte los grandes deseos en hitos medibles que de verdad ocurren.","content":"La mayoría de los objetivos financieros compartidos se quedan en conversación de sobremesa porque les falta una cosa: un número y una fecha. Sin eso, son intenciones, no planes. Viajar, mudarse, formar familia o crear un colchón de emergencia necesitan estructura.\n\nDefine el objetivo en una frase concreta: 'Ahorrar 6.000 € para mudarnos en septiembre de 2027'. Ahora divide entre los meses que faltan. Ese es tu aporte mensual real, no una estimación romántica.\n\nCuando hablas de ahorro en pareja, conviene diferenciar entre deseo y compromiso. El deseo es lo que os gustaría que pasara; el compromiso es la cantidad mensual que ambos aceptáis reservar. Si esa cifra aprieta demasiado, el objetivo necesita más tiempo o menos ambición.\n\nCrea una cuenta o categoría separada para ese objetivo. Si vive mezclado con el día a día, desaparece entre supermercado, ocio y recibos. Si tiene su propio espacio, crece a la vista de todos y se convierte en una meta financiera tangible.\n\nUn plan financiero familiar también necesita prioridades. No todos los objetivos pueden avanzar al mismo ritmo. Puede que durante tres meses tenga sentido reforzar el fondo de emergencia y después volver al viaje. Lo importante es que el cambio sea consciente, no improvisado.\n\nRevisa el avance una vez al mes, junto con tu presupuesto. Ver el porcentaje subir mantiene vivo el hábito cuando la motivación inicial se apaga. Y si un mes no se puede aportar, se registra sin drama y se ajusta el calendario.","featured_image":"/blog/blog-objetivos-compartidos-cover.jpg","category":"objetivos","author":"Karma Financiero","status":"published","published_at":"2026-05-28T09:00:00.000Z","seo_title":"Objetivos compartidos: del 'algún día' al primer paso real","seo_description":"Viajar, mudarse, formar familia, dejar un trabajo. Convierte los grandes deseos en hitos medibles que de verdad ocurren."},{"title":"Cuentas comunes sin perder independencia","slug":"cuentas-comunes-sin-perder-independencia","excerpt":"Cómo decidir qué va a la cuenta compartida, qué se queda en lo personal y qué reglas evitan malentendidos.","content":"Compartir gastos no significa fundir toda la vida financiera en una sola cuenta. De hecho, muchas parejas funcionan mejor cuando combinan una cuenta común clara con espacios personales respetados.\n\nLa cuenta común debería cubrir lo que sostiene la convivencia: alquiler o hipoteca, suministros, supermercado, seguros, mascotas, hijos si los hay y cualquier gasto que ambos reconozcan como compartido. Ese límite evita que cada pago tenga que negociarse desde cero.\n\nLo personal necesita el mismo respeto. Cafés, aficiones, regalos, ropa o planes individuales no deberían convertirse en una auditoría constante. La independencia baja la tensión y hace más sana la conversación sobre finanzas compartidas.\n\nEl punto delicado es la proporción. Si los ingresos son parecidos, repartir gastos en pareja al 50% puede funcionar. Si no lo son, suele ser más justo aportar por porcentaje de ingresos. La pregunta útil no es quién paga más, sino si el esfuerzo se siente equilibrado.\n\nTambién conviene decidir qué pasa con gastos mixtos: una escapada, muebles, regalos familiares o compras grandes. Podéis crear una categoría temporal dentro de la cuenta común para que esos pagos no desordenen el presupuesto del mes.\n\nLa regla debe estar escrita y revisarse cuando cambie la realidad. Nuevos ingresos, paro, mudanza, hijos o una deuda pendiente cambian el sistema. Las buenas cuentas comunes no son rígidas: son transparentes.","featured_image":"/blog/blog-cuenta-comun-cover.jpg","category":"pareja","author":"Karma Financiero","status":"published","published_at":"2026-06-19T09:00:00.000Z","seo_title":"Cuentas comunes sin perder independencia","seo_description":"Cómo decidir qué va a la cuenta compartida, qué se queda en lo personal y qué reglas evitan malentendidos."},{"title":"Los gastos invisibles que desordenan un hogar","slug":"gastos-invisibles-del-hogar","excerpt":"Suscripciones, recambios, pequeños pagos y compras repetidas: el mapa para encontrarlos antes de que pesen.","content":"Los gastos invisibles que rompen un presupuesto rara vez llegan con luces de emergencia. Suelen ser pequeños, repetidos y fáciles de justificar: una suscripción que ya no usas, un envío urgente, una compra semanal que nadie registró.\n\nPara encontrarlos, revisa los últimos treinta días y marca todo lo que se repite sin haber sido decidido. No se trata de cancelar por cancelar, sino de recuperar intención sobre el dinero que sale en automático.\n\nEl control de suscripciones es uno de los primeros lugares donde aparece ahorro familiar. Plataformas duplicadas, apps que ya no se usan, cuotas anuales olvidadas o servicios contratados por urgencia pueden sumar mucho más de lo que parece.\n\nDespués mira los recambios y compras pequeñas: pilas, farmacia, menaje, envíos, cafés, snacks, comisiones y pagos de última hora. No son enemigos del presupuesto, pero necesitan un lugar. Si no tienen categoría, siempre parecen excepciones.\n\nPara reducir gastos del hogar sin recortar bienestar, elige una acción por semana. Cancelar una suscripción, agrupar compras, planificar una comida más en casa o revisar tarifas. Los cambios pequeños sostenidos funcionan mejor que una austeridad intensa que dura diez días.\n\nCuando esos gastos se vuelven visibles, la sensación cambia. No porque el hogar deje de gastar, sino porque vuelve a elegir. Y elegir con calma es una forma muy concreta de ahorrar.","featured_image":"/blog/blog-gastos-invisibles-cover.jpg","category":"ahorro","author":"Karma Financiero","status":"published","published_at":"2026-06-26T09:00:00.000Z","seo_title":"Los gastos invisibles que desordenan un hogar","seo_description":"Suscripciones, recambios, pequeños pagos y compras repetidas: el mapa para encontrarlos antes de que pesen."},{"title":"La reunión financiera de quince minutos","slug":"reunion-financiera-de-quince-minutos","excerpt":"Un guion simple para revisar cuentas compartidas sin convertirlo en una tarde de tensión.","content":"Una reunión financiera no necesita una mesa enorme ni dos horas de energía perfecta. Quince minutos bien usados pueden evitar muchas conversaciones difíciles acumuladas y mejorar la organización financiera del hogar.\n\nEmpieza por los hechos: ingresos recibidos, gastos importantes, pagos pendientes y saldo de objetivos. Durante los primeros cinco minutos nadie interpreta ni culpa, solo se mira el mapa.\n\nLos siguientes cinco minutos son para decidir: qué pago falta, qué categoría se está pasando y qué ajuste pequeño ayuda al mes. Una sola decisión clara vale más que diez ideas vagas.\n\nReserva los últimos minutos para la revisión de gastos compartidos. ¿Hay algo que se repite? ¿Alguna compra que debería ir a una categoría común? ¿Un objetivo que necesita más o menos aportación? Estas preguntas convierten el dinero en una tarea manejable.\n\nSi vivís en pareja o compartís casa, dejad por escrito el acuerdo de la semana. Puede ser una nota simple: 'bajamos ocio 40 €, revisamos suscripciones y aportamos 100 € al colchón'. Lo importante es que la decisión no dependa de la memoria.\n\nCierra con algo que haya salido bien. Puede sonar menor, pero terminar reconociendo avance cambia el tono de la próxima reunión. El dinero compartido también necesita memoria amable.","featured_image":"/blog/blog-reunion-financiera-cover.jpg","category":"rituales","author":"Karma Financiero","status":"published","published_at":"2026-07-01T09:00:00.000Z","seo_title":"La reunión financiera de quince minutos","seo_description":"Un guion simple para revisar cuentas compartidas sin convertirlo en una tarde de tensión."}]$json$::jsonb)
    as item(
      title text,
      slug text,
      excerpt text,
      content text,
      featured_image text,
      category text,
      author text,
      status text,
      published_at timestamptz,
      seo_title text,
      seo_description text
    )
)
insert into public.blog_posts (
  title,
  slug,
  excerpt,
  content,
  featured_image,
  category,
  author,
  status,
  published_at,
  seo_title,
  seo_description
)
select
  title,
  slug,
  excerpt,
  content,
  featured_image,
  category,
  author,
  status,
  published_at,
  seo_title,
  seo_description
from post_rows
on conflict (slug) do update
set title = excluded.title,
    excerpt = excluded.excerpt,
    content = excluded.content,
    featured_image = excluded.featured_image,
    category = excluded.category,
    author = excluded.author,
    status = excluded.status,
    published_at = excluded.published_at,
    seo_title = excluded.seo_title,
    seo_description = excluded.seo_description;
